/**
 * Synchronous token counting with improved approximation
 *
 * Uses heuristics calibrated against cl100k_base encoding:
 * - Base: ~4 chars/token for prose
 * - Code: ~3.5 chars/token (more symbols/short identifiers)
 * - Whitespace: collapses to fewer tokens
 * - Punctuation: often separate tokens
 */
export const countTokensApprox = (text: string): number => {
  if (text.length === 0) return 0

  // Count different character types for weighted estimation
  const codeBlockMatches = text.match(/```[\s\S]*?```|`[^`]+`/g)
  const codeLength = codeBlockMatches
    ? codeBlockMatches.reduce((sum, m) => sum + m.length, 0)
    : 0
  const proseLength = text.length - codeLength

  // Count punctuation that typically becomes separate tokens
  const punctuationCount = (
    text.match(/[{}[\](),.;:!?<>@#$%^&*=+|\\/"'-]/g) || []
  ).length

  // Count whitespace sequences (collapse to single tokens)
  const whitespaceSequences = (text.match(/\s+/g) || []).length

  // Estimate tokens:
  // - Prose: ~4 chars/token
  // - Code: ~3.5 chars/token (shorter identifiers, more symbols)
  // - Add punctuation as mostly individual tokens
  // - Subtract some for whitespace collapsing
  const proseTokens = proseLength / 4
  const codeTokens = codeLength / 3.5
  const punctuationBonus = punctuationCount * 0.3 // ~30% of punctuation adds a token
  const whitespaceDiscount = whitespaceSequences * 0.2 // slight reduction for collapsed whitespace

  const estimate =
    proseTokens + codeTokens + punctuationBonus - whitespaceDiscount

  // Add 10% safety margin to avoid under-counting
  return Math.ceil(estimate * 1.1)
}

