  // Count punctuation that typically becomes separate tokens
  const punctuationCount = (
    text.match(/[{}[\](),.;:!?<>@#$%^&*=+|\\/"'-]/g) || []
  ).length

  // Count whitespace sequences (collapse to single tokens)
  const whitespaceSequences = (text.match(/\s+/g) || []).length

  // Count newlines separately - they often tokenize individually
  const newlineCount = (text.match(/\n/g) || []).length

  // Estimate tokens:
  // - Prose: ~4 chars/token
  // - Code: ~3 chars/token (shorter identifiers, more symbols - reduced from 3.5)
  // - Add punctuation as mostly individual tokens
  // - Add newlines as they often tokenize separately
  // - Subtract some for whitespace collapsing
  const proseTokens = proseLength / 4
  const codeTokens = codeLength / 3 // More conservative for code (was 3.5)
  const punctuationBonus = punctuationCount * 0.4 // ~40% of punctuation adds a token (was 0.3)
  const newlineBonus = newlineCount * 0.5 // newlines often become tokens
  const whitespaceDiscount = whitespaceSequences * 0.15 // slight reduction for collapsed whitespace

  const estimate =
    proseTokens +
    codeTokens +
    punctuationBonus +
    newlineBonus -
    whitespaceDiscount

  // Add 20% safety margin to avoid under-counting (increased from 10%)
  // This helps handle edge cases where tokenization is unpredictable
  return Math.ceil(estimate * 1.2)
}

